@Test
@DisplayName("should reject enrollment when turma is full")
void shouldRejectEnrollment_whenTurmaIsFull() {
    // Arrange
    var turma = TurmaBuilder.umaTurma().comVagas(0).build();
    when(repository.find(anyLong())).thenReturn(turma);

    // Act & Assert
    var ex = assertThrows(SenaiException.class, 
